import 'dart:typed_data';import 'package:flutter_riverpod/flutter_riverpod.dart';
import '../../../data/models/course.dart';import '../../../data/models/import_result.dart';import '../../../data/datasources/remote/jw_login_service.dart';import '../../../domain/usecases/import_courses_usecase.dart';import '../../../data/repositories/course_repository.dart';
final courseRepositoryProvider=Provider<CourseRepository>((ref)=>CourseRepository());final importUseCaseProvider=Provider<ImportCoursesUseCase>((ref){final r=ref.watch(courseRepositoryProvider);return ImportCoursesUseCase(r);});final importStateProvider=StateNotifierProvider<ImportNotifier,ImportState>((ref){final uc=ref.watch(importUseCaseProvider);return ImportNotifier(uc);});
class ImportState{final bool isLoading;final String? errorMessage;final List<Course> previewCourses;final String? successMessage;final String selectedSystem;final Uint8List? captchaBytes;const ImportState({this.isLoading=false,this.errorMessage,this.previewCourses=const[],this.successMessage,this.selectedSystem='auto',this.captchaBytes});ImportState copyWith({bool? isLoading,String? errorMessage,List<Course>? previewCourses,String? successMessage,String? selectedSystem,Uint8List? captchaBytes,bool clearError=false,bool clearSuccess=false,bool clearCaptcha=false})=>ImportState(isLoading:isLoading??this.isLoading,errorMessage:clearError?null:(errorMessage??this.errorMessage),previewCourses:previewCourses??this.previewCourses,successMessage:clearSuccess?null:(successMessage??this.successMessage),selectedSystem:selectedSystem??this.selectedSystem,captchaBytes:clearCaptcha?null:(captchaBytes??this.captchaBytes));}
class ImportNotifier extends StateNotifier<ImportState>{final ImportCoursesUseCase _uc;ImportNotifier(this._uc):super(const ImportState());void setSystemType(String t){state=state.copyWith(selectedSystem:t);}Future<void> loginAndImport({required String schoolUrl,required String username,required String password,required String captcha,ProxyConfig? proxy})async{state=state.copyWith(isLoading:true,clearError:true,clearSuccess:true);final result=await _uc.loginAndFetch(schoolUrl:schoolUrl,username:username,password:password,captcha:captcha,st:state.selectedSystem,proxy:proxy);if(result.success){state=state.copyWith(isLoading:false,previewCourses:result.courses,successMessage:result.message,clearCaptcha:true);}else{state=state.copyWith(isLoading:false,errorMessage:result.message);}}Future<void> importFromHtml(String html)async{state=state.copyWith(isLoading:true,clearError:true,clearSuccess:true);final result=_uc.importFromHtml(html,state.selectedSystem);if(result.success){state=state.copyWith(isLoading:false,previewCourses:result.courses,successMessage:result.message);}else{state=state.copyWith(isLoading:false,errorMessage:result.message);}}Future<void> importFromIcs(String ics)async{state=state.copyWith(isLoading:true,clearError:true,clearSuccess:true);final result=_uc.importFromIcs(ics);if(result.success){state=state.copyWith(isLoading:false,previewCourses:result.courses,successMessage:result.message);}else{state=state.copyWith(isLoading:false,errorMessage:result.message);}}Future<void> saveCourses({int sid=0})async{state=state.copyWith(isLoading:true,clearError:true,clearSuccess:true);final result=await _uc.saveImportedCourses(state.previewCourses,sid:sid);if(result.success){state=state.copyWith(isLoading:false,successMessage:result.message,previewCourses:const[]);}else{state=state.copyWith(isLoading:false,errorMessage:result.message);}}void importFromJson(ImportResult r){if(r.success){state=state.copyWith(isLoading:false,previewCourses:r.courses,successMessage:r.message);}else{state=state.copyWith(isLoading:false,errorMessage:r.message);}}void clearPreview(){state=state.copyWith(previewCourses:const[]);}}
